function initializeNotes(){dom.gmNotes.value=localStorage.getItem(storageKeys.notes)||"";document.getElementById("save-notes").addEventListener("click",()=>{localStorage.setItem(storageKeys.notes,dom.gmNotes.value);setNotesStatus("Notes MJ sauvegardees.");});document.getElementById("clear-notes").addEventListener("click",()=>{dom.gmNotes.value="";localStorage.removeItem(storageKeys.notes);setNotesStatus("Notes MJ effacees.");});}
function applyMapZoom(){if(dom.mapZoomStage)dom.mapZoomStage.style.transform=`scale(${mapZoomLevel})`;}
function setMapZoom(nextZoom){mapZoomLevel=Math.max(1,Math.min(2.5,Number(nextZoom)||1));applyMapZoom();}
function getMapZoneState(){return loadJson(storageKeys.mapZones,{});}
function setMapZoneState(state){saveJson(storageKeys.mapZones,state);}
function zoneStateKey(mapKey,zoneId){return `${mapKey}:${zoneId}`;}
function isZoneRevealed(mapKey,zoneId){const state=getMapZoneState();return Boolean(state[zoneStateKey(mapKey,zoneId)]);}
function setZoneRevealed(mapKey,zoneId,revealed){const state=getMapZoneState();state[zoneStateKey(mapKey,zoneId)]=Boolean(revealed);setMapZoneState(state);}
function setAllZones(mapKey,revealed){const map=mapData[mapKey];const state=getMapZoneState();(map.zones||[]).forEach((zone)=>{state[zoneStateKey(mapKey,zone.id)]=Boolean(revealed);});setMapZoneState(state);}
function renderMapPoint(mapKey,pointIndex){const map=mapData[mapKey],point=map.points[pointIndex];dom.mapPointTitle.textContent=point.name;dom.mapPointDescription.textContent=point.description;document.querySelectorAll(".map-hotspot").forEach((node,index)=>node.classList.toggle("active",index===pointIndex));}
function renderMapZones(mapKey){const map=mapData[mapKey];dom.mapZoneOverlay.innerHTML="";dom.mapZoneControls.innerHTML="";(map.zones||[]).forEach((zone)=>{const revealed=isZoneRevealed(mapKey,zone.id);const button=document.createElement("button");button.type="button";button.className=`ghost-button map-zone-button${revealed?" is-revealed":""}`;button.textContent=`${revealed?"Masquer":"Reveler"} ${zone.label}`;button.addEventListener("click",()=>{setZoneRevealed(mapKey,zone.id,!revealed);renderMapZones(mapKey);renderMap(mapKey);});dom.mapZoneControls.appendChild(button);if(!revealed){const mask=document.createElement("div");mask.className="map-zone-mask";mask.style.left=`${zone.x}%`;mask.style.top=`${zone.y}%`;mask.style.width=`${zone.width}%`;mask.style.height=`${zone.height}%`;mask.dataset.label=zone.label;dom.mapZoneOverlay.appendChild(mask);}});}
function renderMap(key){const map=mapData[key];document.querySelectorAll(".map-card").forEach((card)=>card.classList.toggle("active",card.dataset.map===key));dom.mapFocusImage.src=map.image;dom.mapFocusTitle.textContent=map.title;dom.mapFocusDescription.textContent=map.description;dom.mapPoints.innerHTML="";dom.mapHotspots.innerHTML="";setMapZoom(1);map.points.forEach((point,index)=>{const tag=document.createElement("button");tag.type="button";tag.className="tag";tag.textContent=point.name;tag.addEventListener("click",()=>renderMapPoint(key,index));dom.mapPoints.appendChild(tag);const hotspot=document.createElement("button");hotspot.type="button";hotspot.className="map-hotspot";hotspot.style.left=`${point.x}%`;hotspot.style.top=`${point.y}%`;hotspot.textContent=index+1;hotspot.dataset.label=point.name;if(point.zone&&!isZoneRevealed(key,point.zone))hotspot.classList.add("hidden");hotspot.addEventListener("click",()=>renderMapPoint(key,index));dom.mapHotspots.appendChild(hotspot);});renderMapZones(key);renderMapPoint(key,0);dom.hideAllMapZones.onclick=()=>{setAllZones(key,false);renderMap(key);};dom.revealAllMapZones.onclick=()=>{setAllZones(key,true);renderMap(key);};}
function initializeMaps(){document.querySelectorAll(".map-card").forEach((card)=>card.addEventListener("click",()=>renderMap(card.dataset.map)));document.getElementById("toggle-map-labels").addEventListener("click",(event)=>{dom.mapHotspots.classList.toggle("is-hidden");event.currentTarget.textContent=dom.mapHotspots.classList.contains("is-hidden")?"Afficher les reperes":"Masquer les reperes";});dom.zoomInMap.addEventListener("click",()=>setMapZoom(mapZoomLevel+0.2));dom.zoomOutMap.addEventListener("click",()=>setMapZoom(mapZoomLevel-0.2));dom.resetMapZoom.addEventListener("click",()=>setMapZoom(1));renderMap("phandaline");}
function generateBoostIdea(){const text=randomItem(boostIdeas);const target=document.getElementById("boost-text");if(target)target.textContent=text;return text;}
function initializeBoost(){const boostButton=document.getElementById("boost-table");const boostModal=document.getElementById("boost-modal");const rerollBoost=document.getElementById("reroll-boost");if(boostButton&&boostModal){boostButton.addEventListener("click",()=>{generateBoostIdea();boostModal.classList.add("open");});}if(rerollBoost){rerollBoost.addEventListener("click",generateBoostIdea);}generateBoostIdea();}
function getLevelFromXp(perPlayerXp){const thresholds=[0,300,900,2700,6500,14000,23000,34000,48000,64000,85000,100000,120000,140000,165000,195000,225000,265000,305000,355000];let level=1;thresholds.forEach((threshold,index)=>{if(perPlayerXp>=threshold)level=index+1;});return Math.min(level,20);}
function renderCurrency(){if(!dom.currencyList)return;const currency=loadJson(storageKeys.currency,defaultCurrency);dom.currencyList.innerHTML="";currency.forEach((coin,index)=>{const card=document.createElement("article");card.className="resource-card";card.innerHTML=`<header><strong>${coin.name}</strong><span>${coin.value}</span></header>`;const controls=document.createElement("div");controls.className="counter-controls";const minus=document.createElement("button");minus.type="button";minus.className="icon-button";minus.textContent="-";minus.addEventListener("click",()=>updateCurrency(index,-1));const plus=document.createElement("button");plus.type="button";plus.className="icon-button";plus.textContent="+";plus.addEventListener("click",()=>updateCurrency(index,1));controls.append(minus,plus);card.appendChild(controls);dom.currencyList.appendChild(card);});}
function updateCurrency(index,delta){const currency=loadJson(storageKeys.currency,defaultCurrency);currency[index].value=Math.max(0,(currency[index].value||0)+delta);saveJson(storageKeys.currency,currency);renderCurrency();}
function renderInventoryItems(){if(!dom.inventoryItemList)return;const items=loadJson(storageKeys.items,defaultInventoryItems);dom.inventoryItemList.innerHTML="";if(!items.length){const empty=document.createElement("article");empty.className="journal-card";empty.textContent="Aucun objet dans l'inventaire pour l'instant.";dom.inventoryItemList.appendChild(empty);return;}items.forEach((item,index)=>{const card=document.createElement("article");card.className="journal-card";card.innerHTML=`<strong>${item.name}</strong><p>Valeur : ${item.value||"-"}</p>`;const qtyRow=document.createElement("div");qtyRow.className="spell-actions";const qtyLabel=document.createElement("span");qtyLabel.textContent="QTE";const minus=document.createElement("button");minus.type="button";minus.className="icon-button";minus.textContent="-";minus.addEventListener("click",()=>updateInventoryItemQty(index,-1));const qtyInput=document.createElement("input");qtyInput.type="number";qtyInput.min="1";qtyInput.value=item.qty;qtyInput.className="xp-input";qtyInput.addEventListener("change",()=>setInventoryItemQty(index,qtyInput.value));const plus=document.createElement("button");plus.type="button";plus.className="icon-button";plus.textContent="+";plus.addEventListener("click",()=>updateInventoryItemQty(index,1));qtyRow.append(qtyLabel,minus,qtyInput,plus);const remove=document.createElement("button");remove.type="button";remove.className="ghost-button";remove.textContent="Retirer";remove.addEventListener("click",()=>removeInventoryItem(index));card.append(qtyRow,remove);dom.inventoryItemList.appendChild(card);});}
function addInventoryItem(){const name=(dom.inventoryItemName?.value||"").trim();const qty=Math.max(1,Number(dom.inventoryItemQty?.value)||1);const value=(dom.inventoryItemValue?.value||"").trim();if(!name)return;const items=loadJson(storageKeys.items,defaultInventoryItems);items.unshift({name,qty,value});saveJson(storageKeys.items,items);dom.inventoryItemName.value="";dom.inventoryItemQty.value="1";dom.inventoryItemValue.value="";renderInventoryItems();}
function updateInventoryItemQty(index,delta){const items=loadJson(storageKeys.items,defaultInventoryItems);if(!items[index])return;items[index].qty=Math.max(1,(Number(items[index].qty)||1)+delta);saveJson(storageKeys.items,items);renderInventoryItems();}
function setInventoryItemQty(index,value){const items=loadJson(storageKeys.items,defaultInventoryItems);if(!items[index])return;items[index].qty=Math.max(1,Number(value)||1);saveJson(storageKeys.items,items);renderInventoryItems();}
function removeInventoryItem(index){const items=loadJson(storageKeys.items,defaultInventoryItems);items.splice(index,1);saveJson(storageKeys.items,items);renderInventoryItems();}
function renderLevelSummary(){if(!dom.inventoryLevelSummary)return;const xp=loadJson(storageKeys.xp,defaultXpState);const perPlayer=Math.floor(xp.groupXp/3);const level=getLevelFromXp(perPlayer);dom.inventoryLevelSummary.innerHTML="";[{label:"EXP par joueur",value:perPlayer},{label:"Niveau actuel",value:level}].forEach((item)=>{const card=document.createElement("article");card.className="xp-card";card.innerHTML=`<strong>${item.label}</strong><p>${item.value}</p>`;dom.inventoryLevelSummary.appendChild(card);});}
function renderResources(){const resources=loadJson(storageKeys.resources,defaultResources);dom.resourceList.innerHTML="";resources.forEach((resource,index)=>{const card=document.createElement("article");card.className="resource-card";card.innerHTML=`<header><strong>${resource.name}</strong><span>${resource.value}</span></header>`;const controls=document.createElement("div");controls.className="counter-controls";const minus=document.createElement("button");minus.type="button";minus.className="icon-button";minus.textContent="-";minus.addEventListener("click",()=>updateResource(index,-resource.step));const plus=document.createElement("button");plus.type="button";plus.className="icon-button";plus.textContent="+";plus.addEventListener("click",()=>updateResource(index,resource.step));controls.append(minus,plus);card.appendChild(controls);dom.resourceList.appendChild(card);});}
function updateResource(index,delta){const resources=loadJson(storageKeys.resources,defaultResources);resources[index].value=Math.max(0,resources[index].value+delta);saveJson(storageKeys.resources,resources);renderResources();}
