function renderXpPanel(){const xp=loadJson(storageKeys.xp,defaultXpState),perPlayer=Math.floor(xp.groupXp/3);dom.xpPanel.innerHTML="";[{label:"EXP du groupe",value:xp.groupXp},{label:"EXP par joueur",value:perPlayer}].forEach((item)=>{const card=document.createElement("article");card.className="xp-card";card.innerHTML=`<strong>${item.label}</strong><p>${item.value}</p>`;dom.xpPanel.appendChild(card);});const adjust=document.createElement("div");adjust.className="xp-manual-controls";const minus=document.createElement("button");minus.type="button";minus.className="icon-button";minus.textContent="-";minus.addEventListener("click",()=>updateXp(-10));const plus=document.createElement("button");plus.type="button";plus.className="icon-button";plus.textContent="+";plus.addEventListener("click",()=>updateXp(10));const manual=document.createElement("input");manual.type="number";manual.min="0";manual.step="10";manual.value=xp.groupXp;manual.className="xp-input";manual.setAttribute("aria-label","EXP totale du groupe");manual.addEventListener("change",()=>setXpTotal(manual.value));const save=document.createElement("button");save.type="button";save.className="ghost-button";save.textContent="Appliquer";save.addEventListener("click",()=>setXpTotal(manual.value));const label=document.createElement("span");label.textContent="Modifier l EXP";adjust.append(minus,plus,manual,save,label);dom.xpPanel.appendChild(adjust);renderLevelSummary();} 
function updateXp(delta){const xp=loadJson(storageKeys.xp,defaultXpState);xp.groupXp=Math.max(0,xp.groupXp+delta);saveJson(storageKeys.xp,xp);renderXpPanel();}
function setXpTotal(value){const xp=loadJson(storageKeys.xp,defaultXpState);xp.groupXp=Math.max(0,Number(value)||0);saveJson(storageKeys.xp,xp);renderXpPanel();}
function renderPlayers(){const players=loadJson(storageKeys.players,defaultPlayers);if(dom.playerNameEditor)dom.playerNameEditor.innerHTML="";if(dom.playerHealthList)dom.playerHealthList.innerHTML="";if(dom.inventoryPlayerNameEditor)dom.inventoryPlayerNameEditor.innerHTML="";if(dom.inventoryPlayerHealthList)dom.inventoryPlayerHealthList.innerHTML="";players.forEach((player,index)=>{if(dom.inventoryPlayerNameEditor){const editor=document.createElement("article");editor.className="player-name-card";editor.innerHTML=`<label>Joueur ${index+1}</label>`;const nameInput=document.createElement("input");nameInput.type="text";nameInput.value=player.name;nameInput.addEventListener("change",()=>updatePlayerField(index,"name",nameInput.value||`Joueur ${index+1}`));editor.appendChild(nameInput);dom.inventoryPlayerNameEditor.appendChild(editor);}const percentage=Math.max(0,Math.round((player.hp/Math.max(1,player.maxHp))*100));const weaponList=(player.weapons||[]).map((weapon)=>weapon.name).join(" | ");if(dom.playerHealthList){const combatCard=document.createElement("article");combatCard.className="player-card";combatCard.innerHTML=`<strong>${player.name}</strong><div class="player-track"><span>${player.hp} / ${player.maxHp} PV</span></div><div class="hp-bar"><span style="width:${percentage}%"></span></div><p><strong>Armes :</strong> ${weaponList}</p><p><strong>CA :</strong> ${player.ac}</p>`;const combatGrid=document.createElement("div");combatGrid.className="player-grid-meta";const wrap=document.createElement("label");wrap.textContent="PV actuels";const input=document.createElement("input");input.type="number";input.min="0";input.value=player.hp;input.addEventListener("change",()=>updatePlayerField(index,"hp",Number(input.value)));wrap.appendChild(input);combatGrid.appendChild(wrap);combatCard.appendChild(combatGrid);dom.playerHealthList.appendChild(combatCard);}if(dom.inventoryPlayerHealthList){const inventoryCard=document.createElement("article");inventoryCard.className="player-card";inventoryCard.innerHTML=`<strong>${player.name}</strong><div class="player-track"><span>${player.hp} / ${player.maxHp} PV</span></div><div class="hp-bar"><span style="width:${percentage}%"></span></div><p><strong>Armes :</strong> ${weaponList}</p>`;const inventoryGrid=document.createElement("div");inventoryGrid.className="player-grid-meta";[{label:"PV actuels",key:"hp",value:player.hp},{label:"PV max",key:"maxHp",value:player.maxHp},{label:"CA",key:"ac",value:player.ac}].forEach((field)=>{const wrap=document.createElement("label");wrap.textContent=field.label;const input=document.createElement("input");input.type="number";input.min="0";input.value=field.value;input.addEventListener("change",()=>updatePlayerField(index,field.key,Number(input.value)));wrap.appendChild(input);inventoryGrid.appendChild(wrap);});inventoryCard.appendChild(inventoryGrid);dom.inventoryPlayerHealthList.appendChild(inventoryCard);}});}
function updatePlayerField(index,key,value){const players=loadJson(storageKeys.players,defaultPlayers);if(key==="name"){players[index][key]=String(value).trim()||`Joueur ${index+1}`;}else{players[index][key]=Math.max(0,Number(value)||0);if(key==="maxHp"||key==="hp")players[index].hp=Math.min(players[index].hp,players[index].maxHp);}saveJson(storageKeys.players,players);renderPlayers();syncBattlePlayers();}
function updateSlotMax(level,delta){const slots=loadJson(storageKeys.slots,defaultSlots),slot=slots.find((item)=>item.level===level);if(!slot)return;slot.max=Math.max(0,slot.max+delta);slot.current=Math.min(slot.current,slot.max);saveJson(storageKeys.slots,slots);renderSlots();renderSpellList(dom.spellSearch.value);}function renderSlots(){const slots=loadJson(storageKeys.slots,defaultSlots);dom.slotBoard.innerHTML="";slots.forEach((slot)=>{const card=document.createElement("article");card.className="slot-card";card.innerHTML=`<strong>Niveau ${slot.level}</strong><p>${slot.current} / ${slot.max}</p>`;const controls=document.createElement("div");controls.className="slot-max-controls";const decrease=document.createElement("button");decrease.type="button";decrease.className="ghost-button slot-adjust-button";decrease.textContent="-";decrease.addEventListener("click",()=>updateSlotMax(slot.level,-1));const increase=document.createElement("button");increase.type="button";increase.className="ghost-button slot-adjust-button";increase.textContent="+";increase.addEventListener("click",()=>updateSlotMax(slot.level,1));const label=document.createElement("span");label.className="slot-max-label";label.textContent="Max";controls.append(decrease,label,increase);const orbs=document.createElement("div");orbs.className="slot-orbs";for(let i=0;i<slot.max;i+=1){const orb=document.createElement("span");orb.className=`slot-orb${i>=slot.current?" used":""}`;orbs.appendChild(orb);}card.append(controls,orbs);dom.slotBoard.appendChild(card);});}
function useSpellSlot(level){if(level===0)return true;const slots=loadJson(storageKeys.slots,defaultSlots),slot=slots.find((item)=>item.level===level);if(!slot||slot.current<=0)return false;slot.current-=1;saveJson(storageKeys.slots,slots);renderSlots();renderSpellList(dom.spellSearch.value);return true;} function rollDiceExpression(expression){const cleaned=String(expression||"").replace(/\s+/g,"").toLowerCase();const match=cleaned.match(/^(\d+)d(\d+)([+-]\d+)?$/);if(!match)return null;const count=Number(match[1]);const faces=Number(match[2]);const modifier=Number(match[3]||0);let total=modifier;const rolls=[];for(let i=0;i<count;i+=1){const roll=rollDie(faces);rolls.push(roll);total+=roll;}return{total,rolls,modifier,expression:`${count}d${faces}${modifier?modifier>0?`+${modifier}`:modifier:""}`};}
function getMonsterType(monster){const haystack=normalizeText(monster.name+" "+(monster.traits||[]).join(" "));if(haystack.includes("mort-vivant")||haystack.includes("zombie")||haystack.includes("goule")||haystack.includes("spectre")||haystack.includes("banshee")||haystack.includes("liche"))return"Mort-vivant";if(haystack.includes("dragon"))return"Dragon";if(haystack.includes("aberration")||haystack.includes("nothic")||haystack.includes("spectateur")||haystack.includes("grick")||haystack.includes("chuul")||haystack.includes("otyugh")||haystack.includes("oblex"))return"Aberration";if(haystack.includes("plante")||haystack.includes("myconide")||haystack.includes("brindille"))return"Plante";if(haystack.includes("fiellon")||haystack.includes("diablion")||haystack.includes("vampire"))return"Fiellon";if(haystack.includes("mage")||haystack.includes("sorcier")||haystack.includes("pretre")||haystack.includes("acolyte")||haystack.includes("lanceur de sorts"))return"Lanceur de sorts";if(haystack.includes("gobelin")||haystack.includes("bugbear")||haystack.includes("hobgobelin")||haystack.includes("orc")||haystack.includes("bandit")||haystack.includes("cultiste")||haystack.includes("mantelet")||haystack.includes("drow")||haystack.includes("kobold")||haystack.includes("gnoll")||haystack.includes("troglodyte")||haystack.includes("roturier")||haystack.includes("drakeide"))return"Humanoide";if(haystack.includes("araignee")||haystack.includes("loup")||haystack.includes("aigle")||haystack.includes("hibours")||haystack.includes("ours")||haystack.includes("basilic")||haystack.includes("bulette")||haystack.includes("chimere")||haystack.includes("triceratops")||haystack.includes("worg")||haystack.includes("strige")||haystack.includes("ogre"))return"Bete / Monstruosite";return"Autre";}
function getMonsterDanger(monster){if(monster.xp<=50)return"Faible";if(monster.xp<=200)return"Moyen";if(monster.xp<=700)return"Eleve";return"Boss";}
function getMonsterZone(monster){const key=monster.id+" "+normalizeText(monster.name);if(/goblin|yeemik|klarg|hobgoblin|bugbear|grol|wolf|worg/.test(key))return"Cragmaw";if(/redbrand|glasstaff|nothic|bandit/.test(key))return"Phandaline";if(/venomfang|banshee|hamun_kost|ash_zombie|stirge|twig_blight|cultist|dragonclaw_tiamat/.test(key))return"Thundertree";if(/spectator|flameskull|ghoul|grick|ochre_jelly|nezznar|drow|spider|revenant|otyugh|oblex|myconid|troglodyte|zombie|skeleton|wraith/.test(key))return"Mine";if(/orc|ogre|gnoll|basilisk|bulette|chimera|chuul|triceratops|eagle|cave_bear|owlbear/.test(key))return"Rencontre";if(/lich|vampire/.test(key))return"Rare / optionnel";return"Divers";}
function renderSpellList(query=""){const term=normalizeText(query.trim());dom.spellList.innerHTML="";spells.filter((spell)=>!term||normalizeText(`${spell.name} ${spell.level} ${spell.school} ${spell.description} ${spell.dice||""}`).includes(term)).forEach((spell)=>{const card=document.createElement("article");card.className="spell-card";card.innerHTML=`<strong>${spell.name}</strong><div class="spell-meta"><span class="pill">Niveau ${spell.level}</span><span class="pill">${spell.school}</span>${spell.dice?`<span class="pill">${spell.dice}</span>`:""}</div><p>${spell.description}</p>`;const actions=document.createElement("div");actions.className="spell-actions";const useButton=document.createElement("button");useButton.type="button";useButton.className="ghost-button";useButton.textContent="Utiliser";useButton.addEventListener("click",()=>{const ok=useSpellSlot(spell.level);useButton.textContent=ok?"Utilise":"Plus d emplacements";window.setTimeout(()=>{useButton.textContent="Utiliser";},1200);});actions.appendChild(useButton);if(spell.dice){const rollButton=document.createElement("button");rollButton.type="button";rollButton.className="ghost-button";rollButton.textContent=`Degats ${spell.dice}`;const result=document.createElement("span");result.className="roll-result";rollButton.addEventListener("click",()=>{const rolled=rollDiceExpression(spell.dice);if(!rolled)return;result.textContent=`${rolled.total} (${rolled.rolls.join(", ")}${rolled.modifier?rolled.modifier>0?` + ${rolled.modifier}`:` - ${Math.abs(rolled.modifier)}`:""})`;});actions.append(rollButton,result);}card.appendChild(actions);dom.spellList.appendChild(card);});}
function addMonsterToCombat(monsterId){const state=getBattleState(),monster=monsters.find((item)=>item.id===monsterId);if(!monster)return;const position=getFreeCell(state,"monster");state.tokens.push({id:`m-${Date.now()}-${Math.floor(Math.random()*1000)}`,monsterId:monster.id,kind:"monster",side:"monster",name:monster.name,hp:monster.hp,maxHp:monster.hp,ac:monster.ac,x:position.x,y:position.y,xpValue:monster.xp,attacks:monster.attacks});state.log.unshift(`${monster.name} rejoint les combattants actifs.`);saveBattleState(state);renderBattlemap();renderMonsters();}
function renderMonsters(){const term=normalizeText((dom.monsterSearch?.value||"").trim());const typeFilter=dom.monsterTypeFilter?.value||"";const dangerFilter=dom.monsterDangerFilter?.value||"";const zoneFilter=dom.monsterZoneFilter?.value||"";const state=getBattleState();const activeMonsterIds=new Set(state.tokens.filter((token)=>token.kind==="monster"&&token.hp>0).map((token)=>token.monsterId));dom.monsterList.innerHTML="";monsters.filter((monster)=>{const type=getMonsterType(monster),danger=getMonsterDanger(monster),zone=getMonsterZone(monster);const haystack=normalizeText(`${monster.name} ${monster.traits.join(" ")} ${monster.attacks.map((attack)=>`${attack.name} ${attack.text} ${attack.dice||""}`).join(" ")} ${type} ${danger} ${zone}`);return(!term||haystack.includes(term))&&(!typeFilter||type===typeFilter)&&(!dangerFilter||danger===dangerFilter)&&(!zoneFilter||zone===zoneFilter);}).forEach((monster)=>{const type=getMonsterType(monster),danger=getMonsterDanger(monster),zone=getMonsterZone(monster);const isActive=activeMonsterIds.has(monster.id);const card=document.createElement("article");card.className="monster-card";card.innerHTML=`<strong>${monster.name}</strong><div class="monster-meta"><span class="pill">PV ${monster.hp}</span><span class="pill">CA ${monster.ac}</span><span class="pill">EXP ${monster.xp}</span><span class="pill">${type}</span><span class="pill">${danger}</span><span class="pill">${zone}</span></div><p><strong>Traits :</strong> ${monster.traits.join(", ")}</p>`;if(isActive){const list=document.createElement("div");list.className="monster-attacks";monster.attacks.forEach((attack)=>{const item=document.createElement("div");item.className="monster-attack";item.innerHTML=`<strong>${attack.name}</strong><p>+${attack.bonus} pour toucher, ${attack.damage} degats${attack.dice?` (${attack.dice})`:""}. ${attack.text}</p>`;if(attack.dice){const controls=document.createElement("div");controls.className="spell-actions";const rollButton=document.createElement("button");rollButton.type="button";rollButton.className="ghost-button";rollButton.textContent=`Lancer ${attack.dice}`;const result=document.createElement("span");result.className="roll-result";rollButton.addEventListener("click",()=>{const rolled=rollDiceExpression(attack.dice);if(!rolled)return;result.textContent=`${rolled.total} (${rolled.rolls.join(", ")}${rolled.modifier?rolled.modifier>0?` + ${rolled.modifier}`:` - ${Math.abs(rolled.modifier)}`:""})`;});controls.append(rollButton,result);item.appendChild(controls);}list.appendChild(item);});card.appendChild(list);}else{const locked=document.createElement("p");locked.className="hint";locked.textContent="Ajoutez ce monstre au combat pour afficher ses attaques.";card.appendChild(locked);}const button=document.createElement("button");button.type="button";button.className="ghost-button";button.textContent="Ajouter";button.addEventListener("click",()=>addMonsterToCombat(monster.id));card.appendChild(button);dom.monsterList.appendChild(card);});}
function applyRest(type){const players=loadJson(storageKeys.players,defaultPlayers),slots=loadJson(storageKeys.slots,defaultSlots);players.forEach((player)=>{player.hp=type==="short"?Math.min(player.maxHp,player.hp+Math.ceil(player.maxHp*0.35)):player.maxHp;});slots.forEach((slot)=>{slot.current=type==="short"?Math.min(slot.max,slot.current+Math.max(1,Math.floor(slot.max/2))):slot.max;});saveJson(storageKeys.players,players);saveJson(storageKeys.slots,slots);renderPlayers();renderSlots();syncBattlePlayers();}
function getFreeCell(state,side){const rows=side==="player"?[5,4,3]:[0,1,2];for(const y of rows){for(let c=0;c<8;c+=1){const x=side==="player"?c:7-c;if(!state.tokens.some((t)=>t.x===x&&t.y===y&&t.hp>0))return{x,y};}}return{x:0,y:0};}
function buildPlayerToken(player,position){return{id:player.id,kind:"player",side:"player",name:player.name,hp:player.hp,maxHp:player.maxHp,ac:player.ac,x:position.x,y:position.y,weapons:player.weapons||[]};}
function syncBattlePlayers(){const state=getBattleState(),players=loadJson(storageKeys.players,defaultPlayers),fixedPositions=[{x:1,y:5},{x:3,y:5},{x:5,y:5}];players.forEach((player,index)=>{const existing=state.tokens.find((token)=>token.kind==="player"&&token.id===player.id);if(existing){existing.name=player.name;existing.hp=player.hp;existing.maxHp=player.maxHp;existing.ac=player.ac;existing.weapons=player.weapons||[];existing.x=fixedPositions[index].x;existing.y=fixedPositions[index].y;}else{state.tokens.push(buildPlayerToken(player,fixedPositions[index]));}});state.tokens=state.tokens.filter((token)=>token.kind!=="player"||players.some((player)=>player.id===token.id));saveBattleState(state);renderBattlemap();}
function renderBattleLegend(){const state=getBattleState();dom.battleLegend.innerHTML="";const monsters=state.tokens.filter((token)=>token.kind==="monster"&&token.hp>0).length;[{label:"Monstres actifs",value:monsters}].forEach((item)=>{const tag=document.createElement("span");tag.className="tag";tag.textContent=`${item.label}: ${item.value}`;dom.battleLegend.appendChild(tag);});}
function renderCombatLog(){}
function selectToken(){}
function moveSelectedToken(){}
function updateCombatantHp(tokenId,delta){const state=getBattleState(),token=state.tokens.find((item)=>item.id===tokenId);if(!token)return;const previousHp=token.hp;token.hp=Math.max(0,Math.min(token.maxHp,token.hp+delta));if(token.kind==="player")syncPlayerHpFromBattle(token);if(token.kind==="monster"&&previousHp>0&&token.hp===0){awardMonsterXp(token.xpValue||0,token.name,state);state.log.unshift(`${token.name} tombe a 0 PV et disparait.`);}saveBattleState(state);renderBattlemap();renderMonsters();}
function renderBattlemap(){const state=getBattleState();dom.battlemap.innerHTML="";state.tokens.filter((token)=>token.hp>0&&token.kind==="monster").forEach((token)=>{const percentage=Math.max(0,Math.round((token.hp/Math.max(1,token.maxHp))*100));const card=document.createElement("article");card.className="combatant-card";card.innerHTML=`<strong>${token.name}</strong><p>Monstre</p><p>${token.hp}/${token.maxHp} PV</p><div class="hp-bar"><span style="width:${percentage}%"></span></div><p>CA ${token.ac}</p>`;const controls=document.createElement("div");controls.className="counter-controls";const minus1=document.createElement("button");minus1.type="button";minus1.className="icon-button";minus1.textContent="-1";minus1.addEventListener("click",()=>updateCombatantHp(token.id,-1));const minus5=document.createElement("button");minus5.type="button";minus5.className="icon-button";minus5.textContent="-5";minus5.addEventListener("click",()=>updateCombatantHp(token.id,-5));const plus1=document.createElement("button");plus1.type="button";plus1.className="icon-button";plus1.textContent="+1";plus1.addEventListener("click",()=>updateCombatantHp(token.id,1));controls.append(minus1,minus5,plus1);card.appendChild(controls);dom.battlemap.appendChild(card);});renderBattleLegend();renderCombatLog();}
function awardMonsterXp(xpValue,monsterName,state){const xp=loadJson(storageKeys.xp,defaultXpState);xp.groupXp+=xpValue;saveJson(storageKeys.xp,xp);state.log.unshift(`${monsterName} est vaincu. Le groupe gagne ${xpValue} EXP.`);renderXpPanel();}
function syncPlayerHpFromBattle(target){if(target.kind!=="player")return;const players=loadJson(storageKeys.players,defaultPlayers),player=players.find((item)=>item.id===target.id);if(player){player.hp=target.hp;saveJson(storageKeys.players,players);renderPlayers();}}
function dealDamageInState(state,targetId,amount){const target=state.tokens.find((token)=>token.id===targetId);if(!target)return null;const previousHp=target.hp;target.hp=Math.max(0,target.hp-amount);syncPlayerHpFromBattle(target);if(target.kind==="monster"&&previousHp>0&&target.hp===0)awardMonsterXp(target.xpValue||0,target.name,state);return target;}
function getManualDamage(){return 0;}
