function initializeBattle(){dom.battleMonsterSelect.innerHTML=monsters.map((monster)=>`<option value="${monster.id}">${monster.name}</option>`).join("");document.getElementById("add-monster-to-map").addEventListener("click",()=>{addMonsterToCombat(dom.battleMonsterSelect.value);});syncBattlePlayers();const state=getBattleState();const hasMonsterTokens=state.tokens.some((token)=>token.kind==="monster");if(!hasMonsterTokens){monsters.forEach((monster)=>{state.tokens.push({id:`m-${monster.id}`,monsterId:monster.id,kind:"monster",side:"monster",name:monster.name,hp:monster.hp,maxHp:monster.hp,ac:monster.ac,x:0,y:0,xpValue:monster.xp,attacks:monster.attacks});});saveBattleState(state);}renderBattlemap();}
function initializeCombat(){renderXpPanel();renderPlayers();renderSlots();renderSpellList();renderMonsters();initializeBattle();dom.spellSearch.addEventListener("input",(event)=>renderSpellList(event.target.value));dom.monsterSearch.addEventListener("input",()=>renderMonsters());dom.monsterTypeFilter?.addEventListener("change",()=>renderMonsters());dom.monsterDangerFilter?.addEventListener("change",()=>renderMonsters());dom.monsterZoneFilter?.addEventListener("change",()=>renderMonsters());document.getElementById("short-rest").addEventListener("click",()=>applyRest("short"));document.getElementById("long-rest").addEventListener("click",()=>applyRest("long"));dom.toggleSpells.addEventListener("click",()=>{const collapsed=dom.spellPanelBody.classList.toggle("hidden");dom.toggleSpells.textContent=`${collapsed?">":"v"} Afficher / masquer`;dom.toggleSpells.setAttribute("aria-expanded",String(!collapsed));});dom.toggleBestiary.addEventListener("click",()=>{const collapsed=dom.bestiaryPanelBody.classList.toggle("hidden");dom.toggleBestiary.textContent=`${collapsed?">":"v"} Afficher / masquer`;dom.toggleBestiary.setAttribute("aria-expanded",String(!collapsed));});}
function initializeResources(){renderResources();renderCurrency();renderInventoryItems();renderLevelSummary();document.getElementById("reset-resources").addEventListener("click",()=>{saveJson(storageKeys.resources,defaultResources);renderResources();});if(dom.inventoryItemForm){dom.inventoryItemForm.addEventListener("submit",(event)=>{event.preventDefault();addInventoryItem();});}}
function init(){normalizeInitialState();initializeTabs();initializeModals();initializeNotes();initializeBoost();initializeResources();initializeJournal();initializeAi();initializeCombat();}
